/// Key changes from .NET Framework:
///   1. Thread.Abort() / Thread.ResetAbort() throw PlatformNotSupportedException
///      in .NET 6+. Replaced with cooperative cancellation via CancellationToken.
///   2. Manual Thread replaced with Task.Run + async pattern for better
///      thread-pool utilization and structured shutdown.
///   3. Blocking GetNextItem() should be made cancellation-aware
///      (accept a CancellationToken) so Stop() doesn't have to wait or force-kill.
///   4. volatile bool _running replaced by CancellationTokenSource — the
///      idiomatic .NET Core mechanism that also unblocks token-aware waits.
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public void Start()
    {
        _workerTask = Task.Run(() => ProcessLoop(_cts.Token));
    }

    private async Task ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Pass the token so blocking calls can be interrupted cooperatively.
                var item = await GetNextItemAsync(token);
                await ProcessItemAsync(item, token);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Graceful shutdown requested — clean up and exit.
                RollbackCurrentTransaction();
                break;
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        timeout ??= TimeSpan.FromSeconds(5);

        // Signal cancellation (replaces _running = false AND Thread.Abort).
        await _cts.CancelAsync();          // .NET 8+; use _cts.Cancel() on .NET 6/7

